{"code":"const prs = github.list_pull_requests({ state: "open" });
const total = prs.length;
const byRepo = {};
for (const pr of prs) {
  byRepo[pr.repo] = (byRepo[pr.repo] || 0) + 1;
}
const maxRepo = Object.entries(byRepo).reduce((a, b) => b[1] > a[1] ? b : a);
({ total, maxRepo: maxRepo[0], count: maxRepo[1], breakdown: byRepo })"}
